checker_dsl:
EXISTS (`SpringPermitAllCall permitAllCall`) {
  OR {
    EXISTS (`AuthorizeCall authorizeCall`) {
      AND {
        OR {
          (`authorizeCall qualifier is HttpSecurityMatcherCall`),
          (`authorizeCall qualifier is HttpSecurityMatchersCall`)
        },
        OR {
          AND {
            (`authorizeCall first argument is LambdaExpr with body equal to permitAllCall`),
            OR {
              (`permitAllCall qualifier is SpringAnyRequestCall`),
              (`permitAllCall qualifier is RegistryRequestMatchersCall`)
            }
          },
          AND {
            (`authorizeCall has zero arguments`),
            EXISTS (`RegistryRequestMatchersCall registryRequestMatchersCall`) {
              AND {
                (`registryRequestMatchersCall qualifier equals authorizeCall`),
                (`permitAllCall qualifier equals registryRequestMatchersCall`)
              }
            }
          },
          EXISTS (`SpringAnyRequestCall anyRequestCall`) {
            AND {
              (`anyRequestCall qualifier equals authorizeCall`),
              (`permitAllCall qualifier equals anyRequestCall`)
            }
          }
        }
      }
    },
    EXISTS (`AuthorizeCall authorizeCall`) {
      AND {
        (`authorizeCall qualifier is VarAccess`),
        OR {
          AND {
            (`authorizeCall first argument is LambdaExpr with body equal to permitAllCall`),
            (`permitAllCall qualifier is RegistryRequestMatchersCall`)
          },
          AND {
            (`authorizeCall has zero arguments`),
            EXISTS (`RegistryRequestMatchersCall registryRequestMatchersCall`) {
              AND {
                (`registryRequestMatchersCall qualifier equals authorizeCall`),
                (`permitAllCall qualifier equals registryRequestMatchersCall`)
              }
            }
          },
          EXISTS (`Variable v`, `HttpSecurityMatcherCall matcherCall`) {
            AND {
              (`variable v has an access equal to authorizeCall qualifier`),
              (`variable v has an access equal to matcherCall qualifier`),
              (`authorizeCall first argument is LambdaExpr with body equal to permitAllCall`),
              (`permitAllCall qualifier is SpringAnyRequestCall`)
            }
          }
        }
      }
    }
  }
}
